#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define MAX_INPUT_LEN 256

// Encrypted flag (generated by generate_encrypted_flag.py)
unsigned char encryptedFlag[] = {
    0x21, 0x15, 0x11, 0x26, 0x14, 0x29, 0x20, 0x61,
    0x24, 0x61, 0x20, 0x01, 0x63, 0x1c, 0x15, 0x0d,
    0x26, 0xfa, 0x61, 0x0d, 0x61, 0x1c, 0xf1, 0x20,
    0x0b, 0x22, 0x06, 0x1b, 0x62, 0x1c, 0x2f,
};

int encryptedFlagLen = 31;

void encrypt(unsigned char *data, size_t len) {
    // Step 1: XOR every byte with 0x42
    for (size_t i = 0; i < len; i++) {
        data[i] ^= 0x42;
    }
    
    // Step 2: Subtract 0x10 from every byte with wrapping
    for (size_t i = 0; i < len; i++) {
        data[i] = (data[i] - 0x10) & 0xFF;
    }
}

int main() {
    char input[MAX_INPUT_LEN];
    
    printf("Enter the flag: ");
    fflush(stdout);
    
    if (fgets(input, MAX_INPUT_LEN, stdin) == NULL) {
        printf("Error reading input.\n");
        return 1;
    }
    
    size_t len = strlen(input);
    if (len > 0 && input[len - 1] == '\n') {
        input[len - 1] = '\0';
        len--;
    }
    
    // Encrypt user input
    unsigned char encrypted_input[MAX_INPUT_LEN];
    memcpy(encrypted_input, input, len);
    encrypt(encrypted_input, len);
    
    // Compare encrypted input with encrypted flag
    if (len == encryptedFlagLen && memcmp(encrypted_input, encryptedFlag, encryptedFlagLen) == 0) {
        printf("Congratulations! You've found the flag!\n");
    } else {
        printf("That doesn't seem quite right...\n");
    }
    
    return 0;
}
